<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;
class WorkerPayoutReview extends Model{use SoftDeletes;protected $fillable=['review_number','worker_id','worker_profile_id','worker_payout_profile_id','review_type','status','country','evidence_type','evidence_summary','private_note','worker_note','reviewer_note','requested_changes','submitted_at','reviewed_at','approved_at','rejected_at','reviewer_id','approved_by_id','rejected_by_id','metadata'];protected $hidden=['private_note','reviewer_note','metadata'];protected function casts():array{return ['submitted_at'=>'datetime','reviewed_at'=>'datetime','approved_at'=>'datetime','rejected_at'=>'datetime','metadata'=>'array'];}public function worker(){return $this->belongsTo(User::class,'worker_id');}public function payoutProfile(){return $this->belongsTo(WorkerPayoutProfile::class,'worker_payout_profile_id');}public function events(){return $this->hasMany(WorkerPayoutReviewEvent::class)->latest('created_at');}public function reviewer(){return $this->belongsTo(User::class,'reviewer_id');}}
